const data = $input.first().json;
const score = data.scoring_breakdown ? Object.values(data.scoring_breakdown).reduce((a, b) => a + b, 0) : data.lead_score || 0;
const classification = score >= 75 ? 'hot' : score >= 40 ? 'warm' : 'cold';
const followupDay = classification === 'hot' ? 1 : classification === 'warm' ? 3 : 7;
const nextFollowup = new Date(Date.now() + followupDay * 24 * 60 * 60 * 1000).toISOString();
return { ...data, final_score: score, classification, followup_day: followupDay, next_followup_at: nextFollowup };
